 1→use tauri::Manager;
 2→#[cfg(desktop)]
 3→use tauri_plugin_global_shortcut::{Code, GlobalShortcutExt, Modifiers, Shortcut, ShortcutState};
 4→
 5→#[cfg_attr(mobile, tauri::mobile_entry_point)]
 6→pub fn run() {
 7→    tauri::Builder::default()
 8→        .setup(|app| {
 9→            #[cfg(desktop)]
10→            {
11→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
12→                let window = app
13→                    .get_webview_window("main")
14→                    .expect("main window not found");
15→
16→                app.handle().plugin(
17→                    tauri_plugin_global_shortcut::Builder::new()
18→                        .with_handler(move |_app, scut, event| {
19→                            if scut == &shortcut && event.state() == ShortcutState::Pressed {
20→                                let visible = window.is_visible().unwrap_or(false);
21→                                let focused = window.is_focused().unwrap_or(false);
22→
23→                                if visible && focused {
24→                                    let _ = window.hide();
25→                                } else if visible {
26→                                    let _ = window.set_focus();
27→                                } else {
28→                                    let _ = window.show();
29→                                    let _ = window.center();
30→                                    let _ = window.set_focus();
31→                                }
32→                            }
33→                        })
34→                        .build(),
35→                )?;
36→
37→                app.global_shortcut().register(shortcut)?;
38→            }
39→
40→            Ok(())
41→        })
42→        .run(tauri::generate_context!())
43→        .expect("error while running tauri application");
44→}
