12→interface UseWindowOptions {
13→  onShow?: () => void;
14→  onHide?: () => void;
15→}
16→
17→export function useWindow(options: UseWindowOptions = {}) {
18→  const onShowRef = useRef(options.onShow);
19→  const onHideRef = useRef(options.onHide);
20→
21→  useEffect(() => {
22→    onShowRef.current = options.onShow;
23→    onHideRef.current = options.onHide;
24→  });
25→
26→  useEffect(() => {
27→    if (!isTauri) return;
28→
29→    let unlisten: (() => void) | undefined;
30→
31→    (async () => {
32→      const { getCurrentWindow } = await import('@tauri-apps/api/window');
33→      const appWindow = getCurrentWindow();
34→
35→      const unlistenFocus = await appWindow.onFocusChanged(({
36→        payload: focused,
37→      }) => {
38→        if (focused) {
39→          onShowRef.current?.();
40→        }
41→      });
42→
43→      unlisten = unlistenFocus;
44→    })();
45→
46→    return () => {
47→      unlisten?.();
48→    };
49→  }, []);
50→
51→  const hideWindow = useCallback(async () => {
52→    if (!isTauri) return;
53→    const { getCurrentWindow } = await import('@tauri-apps/api/window');
54→    await getCurrentWindow().hide();
55→  }, []);
56→
57→  return {
58→    hideWindow,
59→    isTauri,
60→  };
61→}
